// Valider le payload — reference le trigger par nom
// (car $input contient la sortie de Config, pas le payload webhook)
var raw = $('Recevoir nouvelle reservation').first().json;
var data = raw.body || raw;

var required = ['id', 'property_id', 'check_in', 'check_out'];
var missing = required.filter(function(field) { return !data[field]; });

if (missing.length > 0) {
  throw new Error('Champs manquants: ' + missing.join(', '));
}

return [{json: data}];

// ============================================================
// WF04 — Assignation round-robin des taches de menage
// Assigne a chaque tache le staff ayant le moins de taches
// planifiees cette semaine
// ============================================================

// --- Recuperer le staff ---
var staffItems = $('Get staff actif').all();
var staffList = staffItems.map(function(item) { return item.json; });

var reservation = $('Recevoir nouvelle reservation').first().json;

// --- Recuperer la tache checkout (depuis le noeud qui a tourne) ---
// Chemin OUI (checkout existait) : depuis "Get tache checkout existante"
// Chemin NON (checkout cree)     : depuis "Creer tache checkout_clean"
var checkoutTask = null;
try {
  var existingItems = $('Get tache checkout existante').all();
  if (existingItems.length > 0 && existingItems[0].json && existingItems[0].json.id) {
    checkoutTask = existingItems[0].json;
  }
} catch (e) {}

if (!checkoutTask) {
  try {
    var createdItem = $('Creer tache checkout_clean').first();
    if (createdItem && createdItem.json && createdItem.json.id) {
      checkoutTask = createdItem.json;
    }
  } catch (e) {}
}

// --- Recuperer la tache checkin_prep (optionnelle) ---
var checkinTask = null;
try {
  var checkinItem = $('Creer tache checkin_prep').first();
  if (checkinItem && checkinItem.json && checkinItem.json.id) {
    checkinTask = checkinItem.json;
  }
} catch (e) {}

// --- Assignation ---
if (staffList.length === 0) {
  return [{json: {
    assignedCheckout: null,
    assignedCheckin: null,
    warning: 'Aucun personnel de menage actif. Taches non assignees.',
  }}];
}

if (staffList.length === 1) {
  return [{json: {
    assignedCheckout: checkoutTask ? {
      taskId: checkoutTask.id,
      staffId: staffList[0].id,
      staffName: staffList[0].full_name,
      staffEmail: staffList[0].email,
    } : null,
    assignedCheckin: checkinTask ? {
      taskId: checkinTask.id,
      staffId: staffList[0].id,
      staffName: staffList[0].full_name,
      staffEmail: staffList[0].email,
    } : null,
  }}];
}

// Round-robin : alterner entre les staff
var staffIndex = Math.floor(Date.now() / 1000) % staffList.length;
var checkoutStaff = staffList[staffIndex];
var checkinStaff = staffList[(staffIndex + 1) % staffList.length];

return [{json: {
  assignedCheckout: checkoutTask ? {
    taskId: checkoutTask.id,
    staffId: checkoutStaff.id,
    staffName: checkoutStaff.full_name,
    staffEmail: checkoutStaff.email,
  } : null,
  assignedCheckin: checkinTask ? {
    taskId: checkinTask.id,
    staffId: checkinStaff.id,
    staffName: checkinStaff.full_name,
    staffEmail: checkinStaff.email,
  } : null,
}}];

// ============================================================
// WF04 — Email consolide notification staff (Neurolia Immo)
// ============================================================

// --- Configuration ---
var DASHBOARD_URL = $('Config').first().json.DASHBOARD_URL;

var data = $('Assignation round-robin').first().json;
var reservationRaw = $('Recevoir nouvelle reservation').first().json;
var reservation = reservationRaw.body || reservationRaw;
var property = $('Get propriete').first().json;

// --- Colors & Font ---
var C = {
  terra: '#C45C3B', terraLight: '#FBEAE4',
  dark: '#2D2D2D', text: '#4A4A4A', muted: '#888888',
  border: '#E8E6E3', bgPage: '#F5F4F1', bgSunken: '#FAFAF8',
  error: '#DC2626', info: '#2563EB', warningBg: '#FEF3C7', warning: '#D97706',
};
var F = "-apple-system,'Segoe UI',Helvetica,Arial,sans-serif";

// Formatter les heures
var checkInTime = reservation.check_in_time || '';
var checkOutTime = reservation.check_out_time || '';
var checkInDisplay = reservation.check_in + (checkInTime ? ' a ' + checkInTime : '');
var checkOutDisplay = reservation.check_out + (checkOutTime ? ' a ' + checkOutTime : '');

// --- Construire la liste des taches par staff ---
var staffTasks = {};

if (data.assignedCheckout && data.assignedCheckout.staffEmail) {
  var key = data.assignedCheckout.staffEmail;
  if (!staffTasks[key]) {
    staffTasks[key] = { name: data.assignedCheckout.staffName, email: key, tasks: [] };
  }
  staffTasks[key].tasks.push({
    type: 'checkout_clean',
    typeLabel: 'Menage depart',
    date: checkOutDisplay,
    borderColor: C.error,
  });
}

if (data.assignedCheckin && data.assignedCheckin.staffEmail) {
  var key2 = data.assignedCheckin.staffEmail;
  if (!staffTasks[key2]) {
    staffTasks[key2] = { name: data.assignedCheckin.staffName, email: key2, tasks: [] };
  }
  staffTasks[key2].tasks.push({
    type: 'checkin_prep',
    typeLabel: 'Preparation arrivee',
    date: checkInDisplay,
    borderColor: C.info,
  });
}

// --- Generer un email par staff ---
var emails = [];
var staffEmails = Object.keys(staffTasks);

for (var i = 0; i < staffEmails.length; i++) {
  var staff = staffTasks[staffEmails[i]];
  var firstName = staff.name.split(' ')[0];
  var nbTaches = staff.tasks.length;

  // Task cards
  var taskCards = '';
  for (var j = 0; j < staff.tasks.length; j++) {
    var task = staff.tasks[j];
    taskCards += '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="margin:12px 0;border-radius:6px;overflow:hidden;border:1px solid ' + C.border + ';">' +
      '<tr><td style="height:3px;background-color:' + task.borderColor + ';font-size:0;line-height:0;">&nbsp;</td></tr>' +
      '<tr><td style="padding:16px;">' +
      '<table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr>' +
      '<td style="font-family:' + F + ';font-size:15px;font-weight:700;color:' + C.dark + ';">' + task.typeLabel + '</td>' +
      '<td align="right" style="font-family:' + F + ';font-size:12px;font-weight:600;color:' + task.borderColor + ';text-transform:uppercase;letter-spacing:0.06em;">' + task.date + '</td>' +
      '</tr></table>' +
      '<p style="margin:8px 0 4px;font-family:' + F + ';font-size:14px;font-weight:600;color:' + C.dark + ';">' + property.name + '</p>' +
      '<p style="margin:2px 0;font-family:' + F + ';font-size:13px;"><a href="https://maps.google.com/?q=' + encodeURIComponent((property.address || '') + ', ' + (property.city || '')) + '" style="color:' + C.terra + ';text-decoration:none;">' + (property.address || '-') + ', ' + (property.city || '-') + '</a></p>' +
      '<table role="presentation" cellpadding="0" cellspacing="0" style="margin:12px 0 0;font-family:' + F + ';font-size:13px;color:' + C.text + ';">' +
      '<tr><td style="padding:2px 12px 2px 0;color:' + C.muted + ';font-size:12px;">Code</td><td style="font-weight:600;">' + (property.access_code || '-') + '</td></tr>' +
      '<tr><td style="padding:2px 12px 2px 0;color:' + C.muted + ';font-size:12px;">WiFi</td><td>' + (property.wifi_ssid || '-') + ' / ' + (property.wifi_password || '-') + '</td></tr>' +
      '<tr><td style="padding:2px 12px 2px 0;color:' + C.muted + ';font-size:12px;">Voyageur</td><td>' + (reservation.guest_name || '-') + ' (' + (reservation.nb_guests || '-') + ' pers.)</td></tr>' +
      '</table></td></tr></table>';
  }

  // Special requests warning
  var specialHtml = '';
  if (reservation.special_requests) {
    specialHtml = '<div style="background:' + C.warningBg + ';border-radius:4px;padding:8px 12px;margin:12px 0;font-family:' + F + ';font-size:13px;">' +
      '<strong style="color:' + C.warning + ';">Demande speciale :</strong> ' + reservation.special_requests + '</div>';
  }

  // Content
  var content = '<h1 style="font-family:' + F + ';font-size:22px;font-weight:700;color:' + C.dark + ';margin:0 0 4px;">Bonjour ' + firstName + '</h1>' +
    '<p style="font-family:' + F + ';font-size:14px;color:' + C.muted + ';margin:0 0 20px;">Nouvelle reservation a ' + property.name + '</p>' +
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:' + C.bgSunken + ';border-radius:6px;margin:0 0 16px;">' +
    '<tr><td style="text-align:center;padding:14px 8px;">' +
    '<div style="font-family:' + F + ';font-size:28px;font-weight:700;color:' + C.dark + ';">' + nbTaches + '</div>' +
    '<div style="font-family:' + F + ';font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.06em;color:' + C.muted + ';margin-top:4px;">Tache' + (nbTaches > 1 ? 's' : '') + ' assignee' + (nbTaches > 1 ? 's' : '') + '</div>' +
    '</td></tr></table>' +
    taskCards + specialHtml +
    '<table role="presentation" cellpadding="0" cellspacing="0" style="margin:24px auto 0;">' +
    '<tr><td style="background-color:' + C.terra + ';border-radius:4px;">' +
    '<a href="' + DASHBOARD_URL + '/cleaning" style="display:inline-block;padding:12px 28px;font-family:' + F + ';font-size:14px;font-weight:600;color:#FFFFFF;text-decoration:none;">Voir mon planning &rarr;</a>' +
    '</td></tr></table>';

  // Wrap in branded layout
  var html = '<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1.0"/></head>' +
    '<body style="margin:0;padding:0;background-color:' + C.bgPage + ';">' +
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background-color:' + C.bgPage + ';">' +
    '<tr><td align="center" style="padding:32px 16px;">' +
    '<table role="presentation" width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;">' +
    '<tr><td style="padding:0 0 24px 0;"><table role="presentation" cellpadding="0" cellspacing="0"><tr>' +
    '<td style="width:3px;background-color:' + C.terra + ';border-radius:2px;" width="3">&nbsp;</td>' +
    '<td style="padding-left:10px;font-family:' + F + ';font-size:18px;font-weight:700;color:' + C.dark + ';letter-spacing:-0.02em;">Neurolia Immo</td>' +
    '</tr></table></td></tr>' +
    '<tr><td><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background-color:#FFFFFF;border-radius:6px;overflow:hidden;">' +
    '<tr><td style="height:3px;background-color:' + C.terra + ';font-size:0;line-height:0;">&nbsp;</td></tr>' +
    '<tr><td style="padding:32px 28px;">' + content + '</td></tr>' +
    '</table></td></tr>' +
    '<tr><td style="padding:24px 0 0 0;text-align:center;font-family:' + F + ';font-size:12px;color:#999999;">Neurolia Immo &mdash; par Neurolia</td></tr>' +
    '</table></td></tr></table></body></html>';

  var subject = '[Neurolia Immo] ' + nbTaches + ' tache' + (nbTaches > 1 ? 's' : '') + ' assignee' + (nbTaches > 1 ? 's' : '') + ' — ' + property.name;

  emails.push({json: {
    to: staff.email,
    subject: subject,
    html: html,
  }});
}

return emails;

